SELECT 'b0000000-0000-4000-8000-000000000031','hero',0,'{"heading": "Mission & Values", "subheading": "Brazen Therapy exists to provide accessible, affirming, and trauma-informed mental health care that honors people’s full identities, lived experiences, and relationships — a place where you feel safe, understood, and empowered.", "backgroundImage": "/images/community.jpg", "overlay": true, "buttonText": "Book an appointment", "buttonUrl": "https://brazentherapy.clientsecure.me/"}'::jsonb,TRUE
WHERE EXISTS (SELECT 1 FROM pages WHERE id='b0000000-0000-4000-8000-000000000031');
INSERT INTO content_blocks (page_id, block_type, sort_order, content, published)
SELECT 'b0000000-0000-4000-8000-000000000031','text',1,'{"body": "<h3>Be Bold Without Shame</h3><p>We support you in showing up authentically and speaking truthfully. We never stigmatize identity, emotion, or difference.</p>", "alignment": "left"}'::jsonb,TRUE
WHERE EXISTS (SELECT 1 FROM pages WHERE id='b0000000-0000-4000-8000-000000000031');
INSERT INTO content_blocks (page_id, block_type, sort_order, content, published)
SELECT 'b0000000-0000-4000-8000-000000000031','text',2,'{"body": "<h3>Affirmation &amp; Inclusion</h3><p>We welcome diverse communities and intentionally prioritize marginalized populations, including LGBTQIA+ and neurodivergent people. You never have to defend or diminish who you are to receive care.</p>", "alignment": "left"}'::jsonb,TRUE
WHERE EXISTS (SELECT 1 FROM pages WHERE id='b0000000-0000-4000-8000-000000000031');
INSERT INTO content_blocks (page_id, block_type, sort_order, content, published)
SELECT 'b0000000-0000-4000-8000-000000000031','text',3,'{"body": "<h3>Authenticity &amp; Directness</h3><p>Genuine dialogue, openness, and candid communication are essential to meaningful change.</p>", "alignment": "left"}'::jsonb,TRUE
WHERE EXISTS (SELECT 1 FROM pages WHERE id='b0000000-0000-4000-8000-000000000031');
INSERT INTO content_blocks (page_id, block_type, sort_order, content, published)
SELECT 'b0000000-0000-4000-8000-000000000031','text',4,'{"body": "<h3>Accessibility &amp; Community Impact</h3><p>Care should be accessible and sustainable. We widen access through trainee clinicians, sliding-scale fees, insurance participation, and community collaboration.</p>", "alignment": "left"}'::jsonb,TRUE
WHERE EXISTS (SELECT 1 FROM pages WHERE id='b0000000-0000-4000-8000-000000000031');
